use anyhow::{Context, Result};
use std::fs;
use std::path::Path;

const PRE_COMMIT_HOOK: &str = r#"#!/usr/bin/env bash
# File: .git/hooks/pre-commit
# Automatically generated by `vox ci install-hooks`

echo "🦶 Running VoxCI line-endings check..."

# Run the strict line-ending validator, scoping to changed files (--all is not needed here)
cargo run -q -p vox-cli -- ci line-endings --autofix

if [ $? -ne 0 ]; then
    echo "❌ Commit aborted: CRLF line-endings detected. Run the formatter or fix them in your IDE, then git add again."
    exit 1
fi

echo "✅ Line endings OK."
exit 0
"#;

const PRE_PUSH_HOOK: &str = r#"#!/usr/bin/env bash
# File: .git/hooks/pre-push
# Automatically generated by `vox ci install-hooks`

echo "🚀 VoxCI pre-push checks..."

# Guard 1: Doc pipeline lint
echo "  📄 Doc pipeline lint..."
cargo run -q -p vox-doc-pipeline -- --check
if [ $? -ne 0 ]; then
  echo "❌ Push aborted: doc-pipeline --check failed. Fix frontmatter errors above."
  exit 1
fi

# Guard 2: Cargo check for integration tests
echo "  🦀 Checking integration tests..."
cargo check -p vox-integration-tests --tests 2>&1 | grep "^error" | head -20
if [ ${PIPESTATUS[0]} -ne 0 ]; then
  echo "❌ Push aborted: vox-integration-tests failed to compile."
  exit 1
fi

echo "✅ Pre-push checks passed."

# Spawn background watcher for CI status (advisory post-push)
(
  sleep 5
  cargo run -q -p vox-cli -- ci watch-run --advisory
) &

exit 0
"#;

pub fn run(root: &Path) -> Result<()> {
    let git_dir = root.join(".git");
    if !git_dir.is_dir() {
        // Just print a warning, no need to fail the CI step if someone isn't inside a git clone.
        println!(
            "Skipping hook installation: {} is not a valid .git directory",
            git_dir.display()
        );
        return Ok(());
    }

    let hooks_dir = git_dir.join("hooks");
    if !hooks_dir.exists() {
        fs::create_dir_all(&hooks_dir)
            .with_context(|| format!("create {}", hooks_dir.display()))?;
    }

    let pre_commit_path = hooks_dir.join("pre-commit");

    fs::write(&pre_commit_path, PRE_COMMIT_HOOK)
        .with_context(|| format!("write {}", pre_commit_path.display()))?;

    // Make the hook executable on Unix systems
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        if let Ok(mut perms) = fs::metadata(&pre_commit_path).map(|m| m.permissions()) {
            perms.set_mode(0o755);
            let _ = fs::set_permissions(&pre_commit_path, perms);
        }
    }

    println!(
        "✅ Installed Git pre-commit line-endings hook to {}",
        pre_commit_path.display()
    );

    let pre_push_path = hooks_dir.join("pre-push");
    fs::write(&pre_push_path, PRE_PUSH_HOOK)
        .with_context(|| format!("write {}", pre_push_path.display()))?;

    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        if let Ok(mut perms) = fs::metadata(&pre_push_path).map(|m| m.permissions()) {
            perms.set_mode(0o755);
            let _ = fs::set_permissions(&pre_push_path, perms);
        }
    }

    println!(
        "✅ Installed Git pre-push hook to {}",
        pre_push_path.display()
    );

    Ok(())
}
